import { useState } from "react";

const NotFound = () => {
  const navigate = useNavigate();

  const handleClick = () => {
    navigate("/");
  };

  return (
    <div>
      <h1>404 Not Found.</h1>
      <button
        className="bg-blue-500 text-white rounded-md px-3 py-1"
        onClick={handleClick}
      >
        Go To Home
      </button>
    </div>
  );
};

export default NotFound;
